package generator

import (
	"fmt"
	"os"
	"path/filepath"
)

// GenerateBootstrap creates the main_gox_bootstrap.go file that
// exports GoxGetTree for the iOS bridge to call.
//
// This file is auto-generated and should not be edited.
func GenerateBootstrap(projectDir string) error {
	path := filepath.Join(projectDir, "main_gox_bootstrap.go")
	return os.WriteFile(path, []byte(bootstrapCode), 0644)
}

const bootstrapCode = `// Auto-generated by gox. Do not edit.
package main

/*
#include <stdlib.h>
*/
import "C"
import (
	"encoding/json"
	"unsafe"
)

//export GoxGetTree
func GoxGetTree() *C.char {
	tree := render()
	if tree == nil {
		return C.CString("{}")
	}
	data, err := json.Marshal(tree)
	if err != nil {
		return C.CString("{}")
	}
	return C.CString(string(data))
}

//export GoxFreeString
func GoxFreeString(s *C.char) {
	C.free(unsafe.Pointer(s))
}

func main() {}
`

// GenerateGoMod creates a go.mod for the test app if one doesn't exist.
func GenerateGoMod(projectDir, moduleName, goxModulePath string) error {
	modPath := filepath.Join(projectDir, "go.mod")
	if _, err := os.Stat(modPath); err == nil {
		return nil // already exists
	}

	content := fmt.Sprintf(`module %s

go 1.24

require gox v0.0.0

replace gox => %s
`, moduleName, goxModulePath)

	return os.WriteFile(modPath, []byte(content), 0644)
}
